  ?series wdt:P31 wd:Q1363275 .  # Instance of NLCS
  {
    ?series wdt:P1346 wd:Q653772 ;  # Pirates winner
          wdt:P1451 wd:Q826751 .     # Reds runner-up
  } UNION {
    ?series wdt:P1346 wd:Q826751 ;  # Reds winner
          wdt:P1451 wd:Q653772 .     # Pirates runner-up
  }
  ?series wdt:P580 ?startDate .
  FILTER(YEAR(?startDate) >= 1970 && YEAR(?startDate) <= 1979)
  ?game wdt:P361 ?series .
  ?game wdt:P1129 ?attendance .
}
ORDER BY DESC(?attendance)
